CREATE TABLE IF NOT EXISTS "token_group_pricing" ("id" INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY, "site_id" INTEGER NOT NULL, "account_id" INTEGER, "source_key" TEXT NOT NULL, "group" TEXT NOT NULL, "group_name" TEXT, "description" TEXT, "ratio" DOUBLE PRECISION NOT NULL DEFAULT 1, "source" TEXT NOT NULL DEFAULT 'upstream', "model_count" INTEGER NOT NULL DEFAULT 0, "pricing_available" BOOLEAN NOT NULL DEFAULT false, "last_error" TEXT, "refreshed_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), "created_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), "updated_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), FOREIGN KEY ("account_id") REFERENCES "accounts"("id") ON DELETE CASCADE, FOREIGN KEY ("site_id") REFERENCES "sites"("id") ON DELETE CASCADE);
CREATE UNIQUE INDEX "token_group_pricing_source_group_unique" ON "token_group_pricing" ("site_id", "source_key", "group");
CREATE INDEX "token_group_pricing_account_id_idx" ON "token_group_pricing" ("account_id");
CREATE INDEX "token_group_pricing_group_idx" ON "token_group_pricing" ("group");
CREATE INDEX "token_group_pricing_site_id_idx" ON "token_group_pricing" ("site_id");
